                // Fire turns off
                this.isOn = false;
                this.shouldTurnOn = false;
                this.timeToOnDelta = 0f;
                this.isTurningOff = false;
                this.currentHitTime = 0f;
                this.UpdateFireState(true);
            }
        }
    }

