            this.pSystem.Stop();
        }
        if (notify)
        {
            this.NotifyAllNeighbors();
            FireController.Instance.FireChanged(this.isOn ? 1 : -1);
        }
    }

    public void WaterHit(Vector3 normal)
    {
        // Reset timer when hit
        this.isTurningOff = true;
        this.currentHitInterval = 0f;
    }

