                    this.hasDownNeighbor = this.hasDownNeighbor || (this.transform.position.y - neighbor.transform.position.y > this.minNeighborDownDistance);
                }
            }
        }
        else
        {
            this.shouldTurnOn = false;
            this.timeToOnDelta = 0f;
        }
    }

