            if (occlusion)
                inputs.directFlags = inputs.directFlags | DirectSimulationFlags.Occlusion;
            if (transmission)
                inputs.directFlags = inputs.directFlags | DirectSimulationFlags.Transmission;

            mSource.SetInputs(flags, inputs);
